import*as React from"react";import{MEDIA_QUERIES}from"../lib/adaptivity/index.js";import{mediaQueryNull}from"../lib/browser.js";import{useDOM}from"../lib/dom.js";const mediaQueriesCache=new WeakMap;function getMediaQueries(e){return{desktopPlus:e(MEDIA_QUERIES.DESKTOP_PLUS),smallTabletPlus:e(MEDIA_QUERIES.SMALL_TABLET_PLUS),tablet:e(MEDIA_QUERIES.TABLET),smallTablet:e(MEDIA_QUERIES.SMALL_TABLET),mobile:e(MEDIA_QUERIES.MOBILE),mediumHeight:e(MEDIA_QUERIES.MEDIUM_HEIGHT),mobileLandscapeHeight:e(MEDIA_QUERIES.MOBILE_LANDSCAPE_HEIGHT)}}const useMediaQueries=()=>{const i=useDOM()["window"];return React.useMemo(function(){if(!i)return getMediaQueries(mediaQueryNull);var e=mediaQueriesCache.get(i);if(e)return e;e=getMediaQueries(i.matchMedia.bind(i));return mediaQueriesCache.set(i,e),e},[i])};export{useMediaQueries};